def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    # Margin of error: 2% of slide height
    CENTER_MARGIN = 0.02
    def get_image_shapes(slide):
        images = []
        for shape in slide.shapes:
            if shape.is_placeholder and shape.placeholder_format.type == 7:
                images.append(shape)

            if shape.shape_type == 13:  # Picture
                images.append(shape)
        return images

    mod = Presentation(modified_ppt_path)
    try:
        mod_slide = mod.slides[2]
    except IndexError:
        return "Slide 3 missing in modified file.", 0.0
    mod_imgs = get_image_shapes(mod_slide)
    if len(mod_imgs) < 2:
        return f"Expected at least 2 images, found {len(mod_imgs)}.", 0.0
    # Get slide width in EMU (English Metric Units)
    center_x = mod.slide_width / 2

    centered_count = 0
    for img in mod_imgs:
        img_center = img.left + img.width / 2    
        rel_center = abs(img_center - center_x) / mod.slide_width
        if rel_center <= CENTER_MARGIN:
            centered_count += 1
    if centered_count == len(mod_imgs):
        return "Both images are vertically center-aligned.", 1.0
    elif centered_count == 1:
        return "One image is vertically center-aligned.", 0.5
    return "Neither image is vertically center-aligned.", 0.0

